import{_ as e,o,c as i,a2 as t}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"Sistema Anti Yo-Yo","description":"","frontmatter":{},"headers":[],"relativePath":"pt/advanced/anti-yoyo.md","filePath":"pt/advanced/anti-yoyo.md"}'),n={name:"pt/advanced/anti-yoyo.md"};function s(r,a,l,d,c,u){return o(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="sistema-anti-yo-yo" tabindex="-1"><i class="ph ph-arrows-clockwise"></i> Sistema Anti Yo-Yo <a class="header-anchor" href="#sistema-anti-yo-yo" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-arrows-clockwise&quot;&gt;&lt;/i&gt; Sistema Anti Yo-Yo&quot;">​</a></h1><p>Um dos problemas mais irritantes dos sistemas de escalonamento dinâmico é o <strong>Efeito Yo-Yo</strong> (ou ping-pong de qualidade).</p><h2 id="o-problema-central" tabindex="-1"><i class="ph ph-warning-circle"></i> O Problema Central <a class="header-anchor" href="#o-problema-central" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-warning-circle&quot;&gt;&lt;/i&gt; O Problema Central&quot;">​</a></h2><p>Sem um controlo inteligente, o sistema entra num ciclo infinito:</p><ol><li>Os FPS caem devido a uma cena pesada.</li><li>O plugin reduz a qualidade gráfica (e.g., corta a resolução).</li><li>A carga diminui, e os FPS sobem acima da linha base.</li><li>O plugin deduz que há Performance Headroom disponível e restaura a qualidade gráfica ao máximo.</li><li>Os FPS caem novamente. O ciclo repete-se.</li></ol><p>Consequentemente, o jogador sofre com cintilação contínua da qualidade (Quality flickering): as sombras aparecem e desaparecem constantemente, e a imagem &quot;salta&quot; a cada segundo de desfocada para nítida.</p><h2 id="a-solucao-webap-penalty-lockout" tabindex="-1"><i class="ph ph-shield-check"></i> A Solução WebAP: Penalty Lockout <a class="header-anchor" href="#a-solucao-webap-penalty-lockout" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-shield-check&quot;&gt;&lt;/i&gt; A Solução WebAP: Penalty Lockout&quot;">​</a></h2><p>Erradicámos completamente este problema ao implementar o conceito de um Penalty Lockout. É construído sobre dois parâmetros das configurações do plugin.</p><p>Quando o plugin <em>aumenta</em> a qualidade gráfica, ele dispara um temporizador oculto — a <strong>Detection Window</strong> (e.g., 15 segundos). Durante este intervalo, o Indexer monitoriza de perto a estabilidade dos frames.</p><p>Se o FPS cair subitamente durante esta janela, o sistema tira uma conclusão definitiva: <em>«A atualização gráfica anterior foi um erro; o dispositivo não consegue sustentar este nível a longo prazo.»</em></p><p><strong>Uma penalidade é aplicada:</strong></p><ol><li>O plugin diminui imediatamente a qualidade.</li><li>Uma rigorosa <strong>Penalty Lockout Duration</strong> é aplicada (e.g., durante 60 segundos).</li><li>Pela duração deste minuto, é <strong>categoricamente proibido</strong> ao plugin tentar aumentar a qualidade gráfica novamente, mesmo que os FPS disparem e o processador fique inativo.</li></ol><div class="tip custom-block"><p class="custom-block-title">Bloqueio Extenso (Session Lock)</p><p>Se a dinâmica do seu jogo apresentar picos de carga que ocorrem em ondas, e você preferir que a qualidade nunca tente recuperar após a primeira queda, basta especificar um valor enorme no campo <strong>Penalty Lockout Duration</strong> (e.g., <code>600</code> para 10 minutos ou <code>3600</code> para uma hora). Isto efetivamente trava os gráficos num nível baixo consistente até ao fim da sessão de jogo.</p></div><div class="info custom-block"><p class="custom-block-title">Prioridade de Fluidez</p><p>A penalidade bloqueia exclusivamente tentativas de melhorar a renderização. Se o jogador entrar numa cena ainda mais pesada e os FPS caírem abaixo do limite crítico, o plugin ainda pode diminuir a qualidade de emergência. O sistema invariavelmente prioriza a fluidez do jogo sobre os efeitos visuais.</p></div>',14)])])}const g=e(n,[["render",s]]);export{p as __pageData,g as default};
